import React from "react";

const projects = [
  {
    title: "E-Commerce Platform",
    description: "Built a custom Shopware 6 plugin for seamless payment integration and optimization.",
    image: "https://via.placeholder.com/400",
    link: "#",
  },
  {
    title: "Odoo ERP Customization",
    description: "Developed and integrated Odoo ERP modules for improved business automation.",
    image: "https://via.placeholder.com/400",
    link: "#",
  },
  {
    title: "Category Discount Plugin",
    description: "Created a Shopware plugin for dynamic category discounts with banners.",
    image: "https://via.placeholder.com/400",
    link: "#",
  },
];

const Projects = () => {
  return (
    <section className="min-h-screen bg-gray-100 py-12 px-6">
      <div className="container mx-auto text-center">
        <h2 className="text-4xl font-bold text-gray-800 mb-8">My Projects</h2>
        <div className="grid md:grid-cols-3 gap-6">
          {projects.map((project, index) => (
            <div key={index} className="bg-white rounded-lg shadow-lg overflow-hidden transform transition duration-300 hover:scale-105">
              <img src={project.image} alt={project.title} className="w-full h-48 object-cover" />
              <div className="p-6">
                <h3 className="text-2xl font-semibold text-gray-700">{project.title}</h3>
                <p className="text-gray-500 mt-2">{project.description}</p>
                <a href={project.link} className="mt-4 inline-block bg-gradient-to-r from-blue-500 to-purple-600 text-white font-semibold py-2 px-4 rounded-lg shadow-lg hover:from-purple-600 hover:to-blue-500 transition-all">View Project</a>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
